if (!defined('CLI_SCRIPT')) { define('CLI_SCRIPT', true); }
require('/www/moodle/config.php');
require_once($CFG->dirroot . '/course/lib.php');
require_once($CFG->dirroot . '/mod/geogebra/lib.php');
require_once($CFG->dirroot . '/mod/geogebra/locallib.php');
try {
    $course = $DB->get_record('course', ['shortname' => 'GEOGEBRA01'], '*', MUST_EXIST);
    $admin = get_admin();
    \core\session\manager::set_user($admin);
    $now = time();
    $geogebra = (object)[
        'course'        => $course->id,
        'name'          => 'Sample GeoGebra activity',
        'intro'         => '<p>Open this activity to try an embedded GeoGebra applet loaded from a public GeoGebra material.</p>',
        'introformat'   => FORMAT_HTML,
        'filetype'      => GEOGEBRA_FILE_TYPE_EXTERNAL,
        'geogebraurl'   => 'https://www.geogebra.org/material/iframe/id/RHYH3UV8',
        'url'           => 'https://www.geogebra.org/material/iframe/id/RHYH3UV8',
        'urlggb'        => '',
        'language'      => '',
        'seed'          => 1,
        'maxattempts'   => 0,
        'grade'         => 100,
        'grademethod'   => GEOGEBRA_HIGHEST_GRADE,
        'attributes'    => '',
        'showsubmit'    => 1,
        'timeavailable' => 0,
        'timedue'       => 0,
        'timecreated'   => $now,
        'timemodified'  => $now,
    ];
    $module = $DB->get_record('modules', ['name' => 'geogebra'], '*', MUST_EXIST);
    $cm = (object)[
        'course'       => $course->id,
        'module'       => $module->id,
        'instance'     => 0,
        'section'      => 1,
        'idnumber'     => '',
        'added'        => $now,
        'score'        => 0,
        'indent'       => 0,
        'visible'      => 1,
        'visibleold'   => 1,
        'groupmode'    => 0,
        'groupingid'   => 0,
        'completion'   => 0,
        'showdescription' => 0,
    ];
    $cmid = add_course_module($cm);
    $geogebra->coursemodule = $cmid;
    $instanceid = geogebra_add_instance($geogebra, null);
    $DB->set_field('course_modules', 'instance', $instanceid, ['id' => $cmid]);
    course_add_cm_to_section($course->id, $cmid, 1);
    rebuild_course_cache($course->id, true);
    echo "Created mod_geogebra instance id={$instanceid} cmid={$cmid} in course {$course->shortname}\n";
} catch (\Throwable $e) {
    echo 'ERROR: ' . $e->getMessage() . "\n";
}
